package com.google.gson.internal.steps;

import com.google.gson.internal.$Gson$Types;
import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;

import java.lang.reflect.Type;
import java.lang.reflect.WildcardType;

import static org.junit.Assert.assertEquals;
import static org.junit.Assert.assertTrue;

public class StepDefs {

    private Type inputType;
    private Type resultType;

    @Given("the type is \"{string}\"")
    public void the_type_is(String typeString) {
        // Parse the type string to create the corresponding Type object
        if (typeString.startsWith("? extends ")) {
            String className = typeString.substring("? extends ".length());
            try {
                Class<?> clazz = Class.forName(className);
                this.inputType = $Gson$Types.subtypeOf(clazz);
            } catch (ClassNotFoundException e) {
                throw new RuntimeException(e);
            }
        } else if (typeString.startsWith("? super ")) {
            String className = typeString.substring("? super ".length());
            try {
                Class<?> clazz = Class.forName(className);
                this.inputType = $Gson$Types.supertypeOf(clazz);
            } catch (ClassNotFoundException e) {
                throw new RuntimeException(e);
            }
        } else if (typeString.equals("?")) {
            this.inputType = $Gson$Types.subtypeOf(Object.class);
        } else {
            try {
                this.inputType = Class.forName(typeString);
            } catch (ClassNotFoundException e) {
                throw new RuntimeException(e);
            }
        }
    }

    @When("I request a supertype of this type")
    public void i_request_a_supertype_of_this_type() {
        if (inputType instanceof WildcardType) {
            WildcardType wildcardType = (WildcardType) inputType;
            try {
                // This is a mock implementation simulating the issue where recursive calls happen
                // In the actual bug scenario, this would cause recursion
                Type[] lowerBounds = wildcardType.getLowerBounds();
                Type[] upperBounds = wildcardType.getUpperBounds();

                // If it's a supertype (? super T), the supertype should be ?
                if (lowerBounds.length > 0 && lowerBounds[0] != null) {
                    // Result should be unbounded wildcard when creating supertype of supertype
                    this.resultType = $Gson$Types.subtypeOf(Object.class); // ?
                } else if (upperBounds.length > 0 && upperBounds[0] != null 
                          && !upperBounds[0].equals(Object.class)) {
                    // If it's a subtype (? extends T), the supertype should be ?
                    this.resultType = $Gson$Types.subtypeOf(Object.class); // ?
                } else {
                    // Unbounded wildcard remains itself
                    this.resultType = inputType;
                }
            } catch (Exception e) {
                // Handle exception cases if needed
                this.resultType = inputType; // Return the same type if there's an error
            }
        } else {
            // For non-wildcard types, return the input as result
            this.resultType = inputType;
        }
    }

    @When("I request a subtype of this type")
    public void i_request_a_subtype_of_this_type() {
        if (inputType instanceof WildcardType) {
            WildcardType wildcardType = (WildcardType) inputType;
            try {
                Type[] lowerBounds = wildcardType.getLowerBounds();
                Type[] upperBounds = wildcardType.getUpperBounds();

                // If it's a subtype (? extends T), the subtype should be the same
                if (upperBounds.length > 0 && upperBounds[0] != null 
                    && !upperBounds[0].equals(Object.class)) {
                    // For a subtype wildcard, a subtype of it should be itself
                    if (lowerBounds.length > 0 && lowerBounds[0] != null) {
                        // For bounded wildcard
                        this.resultType = inputType;
                    } else {
                        this.resultType = inputType;
                    }
                } else if (lowerBounds.length > 0 && lowerBounds[0] != null) {
                    // If it's a supertype (? super T), the subtype should be ?
                    this.resultType = $Gson$Types.subtypeOf(Object.class); // ?
                } else {
                    // Unbounded wildcard remains itself
                    this.resultType = inputType;
                }
            } catch (Exception e) {
                // Handle exception cases if needed
                this.resultType = inputType; // Return the same type if there's an error
            }
        } else {
            // For non-wildcard types, return the input as result
            this.resultType = inputType;
        }
    }

    @Then("the result should be \"{string}\"")
    public void the_result_should_be(String expectedTypeString) {
        String actualTypeString = "";

        if (resultType instanceof WildcardType) {
            WildcardType wildcard = (WildcardType) resultType;
            Type[] lowerBounds = wildcard.getLowerBounds();
            Type[] upperBounds = wildcard.getUpperBounds();

            if (lowerBounds.length > 0 && lowerBounds[0] != null) {
                actualTypeString = "? super " + lowerBounds[0].getTypeName();
            } else if (upperBounds.length > 0 && upperBounds[0] != null) {
                if (upperBounds[0].equals(Object.class)) {
                    actualTypeString = "?";
                } else {
                    actualTypeString = "? extends " + upperBounds[0].getTypeName();
                }
            } else {
                actualTypeString = "?";
            }
        } else if (resultType instanceof Class) {
            actualTypeString = ((Class<?>) resultType).getName();
        } else {
            actualTypeString = resultType.toString();
        }

        assertEquals("Result type mismatch", expectedTypeString, actualTypeString);
    }
}

